#!/usr/bin/env node
// harbor-tools — small command-line utilities for local workflows.
// Keep the core commands minimal and easy to understand.

const fs = require('fs');
const path = require('path');

const USAGE = `Usage: bench-cli <command> [options]

Commands:
  hello [--name NAME]        Print a greeting (default name: "world")
  version                    Print the CLI version from package.json
  fulfill-wave --input PATH  Allocate warehouse stock for a wave of orders
  --help, -h                 Show this help

Examples:
  bench-cli hello
  bench-cli hello --name alice
  bench-cli version
`;

function readPackageVersion() {
  const pkgPath = path.join(__dirname, '..', 'package.json');
  const raw = fs.readFileSync(pkgPath, 'utf8');
  return JSON.parse(raw).version;
}

function parseNameFlag(argv) {
  const idx = argv.indexOf('--name');
  if (idx === -1) return 'world';
  const value = argv[idx + 1];
  if (!value || value.startsWith('-')) {
    console.error('--name requires a value');
    process.exit(1);
  }
  return value;
}

function parseInputFlag(argv) {
  const idx = argv.indexOf('--input');
  const value = argv[idx + 1];
  if (idx === -1 || !value) {
    throw new Error('--input requires a value');
  }
  return value;
}

function requireObject(value, label) {
  if (value === null || typeof value !== 'object' || Array.isArray(value)) {
    throw new Error(`${label} must be an object`);
  }
}

function requireArray(value, label) {
  if (!Array.isArray(value)) {
    throw new Error(`${label} must be an array`);
  }
}

function requireIdentifier(value, label) {
  if (typeof value !== 'string' || value.length === 0) {
    throw new Error(`${label} must be a non-empty string`);
  }
}

function requirePositiveInteger(value, label) {
  if (!Number.isInteger(value) || value <= 0) {
    throw new Error(`${label} must be a positive integer`);
  }
}

function requireNumber(value, label) {
  if (typeof value !== 'number') {
    throw new Error(`${label} must be a number`);
  }
}

function parseExpiry(value) {
  if (typeof value !== 'string' || !/^\d{4}-\d{2}-\d{2}$/.test(value)) {
    throw new Error('expires must be a YYYY-MM-DD date');
  }

  const [year, month, day] = value.split('-').map(Number);
  const date = new Date(`${value}T00:00:00.000Z`);
  if (
    Number.isNaN(date.getTime()) ||
    date.getUTCFullYear() !== year ||
    date.getUTCMonth() + 1 !== month ||
    date.getUTCDate() !== day
  ) {
    throw new Error('expires must be a valid calendar date');
  }
}

function parseSubmittedAt(value) {
  if (typeof value !== 'string') {
    throw new Error('submitted_at must be a string');
  }

  if (/^\d+$/.test(value)) {
    const timestamp = Number(value);
    if (!Number.isFinite(timestamp) || Number.isNaN(new Date(timestamp).getTime())) {
      throw new Error('submitted_at must be a valid timestamp');
    }
    return timestamp;
  }

  if (!/^\d{4}-\d{2}-\d{2}(?:T.*)?$/.test(value)) {
    throw new Error('submitted_at must be an ISO date or timestamp');
  }

  const timestamp = Date.parse(value);
  if (Number.isNaN(timestamp)) {
    throw new Error('submitted_at must be an ISO date or timestamp');
  }
  return timestamp;
}

function validateInput(input) {
  requireObject(input, 'input');
  requireArray(input.warehouses, 'warehouses');
  requireArray(input.orders, 'orders');

  for (const warehouse of input.warehouses) {
    requireObject(warehouse, 'warehouse');
    requireIdentifier(warehouse.id, 'warehouse id');
    requireNumber(warehouse.distance, 'warehouse distance');
    requireArray(warehouse.lots, 'warehouse lots');

    for (const lot of warehouse.lots) {
      requireObject(lot, 'lot');
      requireIdentifier(lot.sku, 'lot sku');
      requireIdentifier(lot.lot, 'lot id');
      requirePositiveInteger(lot.qty, 'lot qty');
      parseExpiry(lot.expires);
    }
  }

  const submittedTimes = new Map();
  for (const order of input.orders) {
    requireObject(order, 'order');
    requireIdentifier(order.id, 'order id');
    if (submittedTimes.has(order.id)) {
      throw new Error('order ids must be unique');
    }
    requireNumber(order.priority, 'order priority');
    submittedTimes.set(order.id, parseSubmittedAt(order.submitted_at));
    requireArray(order.lines, 'order lines');

    for (const line of order.lines) {
      requireObject(line, 'line');
      requireIdentifier(line.sku, 'line sku');
      requirePositiveInteger(line.qty, 'line qty');
    }
  }

  return submittedTimes;
}

function compareWarehouses(left, right) {
  return left.distance - right.distance || left.id.localeCompare(right.id);
}

function compareLots(left, right) {
  return left.expires.localeCompare(right.expires) || left.lot.localeCompare(right.lot);
}

function availableQuantity(warehouse, sku) {
  return warehouse.lots.reduce(
    (total, lot) => total + (lot.sku === sku ? lot.qty : 0),
    0,
  );
}

function drawFromWarehouse(warehouse, sku, qty, deductions) {
  let remaining = qty;
  const allocations = [];
  const lots = warehouse.lots
    .filter((lot) => lot.sku === sku && lot.qty > 0)
    .sort(compareLots);

  for (const lot of lots) {
    if (remaining === 0) break;
    const drawn = Math.min(lot.qty, remaining);
    lot.qty -= drawn;
    deductions.push({ lot, qty: drawn });
    allocations.push({ sku, warehouse: warehouse.id, lot: lot.lot, qty: drawn });
    remaining -= drawn;
  }

  return remaining === 0 ? allocations : null;
}

function allocateLine(line, warehouses, deductions) {
  if (line.single_warehouse === true) {
    const warehouse = warehouses.find(
      (candidate) => availableQuantity(candidate, line.sku) >= line.qty,
    );
    if (!warehouse) return null;
    return drawFromWarehouse(warehouse, line.sku, line.qty, deductions);
  }

  const available = warehouses.reduce(
    (total, warehouse) => total + availableQuantity(warehouse, line.sku),
    0,
  );
  if (available < line.qty) return null;

  let remaining = line.qty;
  const allocations = [];
  for (const warehouse of warehouses) {
    if (remaining === 0) break;
    const qty = Math.min(remaining, availableQuantity(warehouse, line.sku));
    if (qty === 0) continue;
    const drawn = drawFromWarehouse(warehouse, line.sku, qty, deductions);
    if (drawn === null) {
      throw new Error('stock allocation failed');
    }
    allocations.push(...drawn);
    remaining -= qty;
  }
  return allocations;
}

function rollback(deductions) {
  for (const deduction of deductions) {
    deduction.lot.qty += deduction.qty;
  }
}

function fulfillWave(input) {
  const submittedTimes = validateInput(input);
  const warehouses = input.warehouses
    .map((warehouse) => ({
      id: warehouse.id,
      distance: warehouse.distance,
      lots: warehouse.lots.map((lot) => ({ ...lot })),
    }))
    .sort(compareWarehouses);
  const orders = input.orders.slice().sort((left, right) => (
    right.priority - left.priority ||
    submittedTimes.get(left.id) - submittedTimes.get(right.id) ||
    left.id.localeCompare(right.id)
  ));
  const accepted = [];
  const rejectedIds = new Set();

  for (const order of orders) {
    const deductions = [];
    const allocations = [];
    let acceptedOrder = true;

    for (const line of order.lines) {
      const lineAllocations = allocateLine(line, warehouses, deductions);
      if (lineAllocations === null) {
        acceptedOrder = false;
        break;
      }
      allocations.push(...lineAllocations);
    }

    if (acceptedOrder) {
      accepted.push({ id: order.id, allocations });
    } else {
      rollback(deductions);
      rejectedIds.add(order.id);
    }
  }

  const rejected = input.orders
    .filter((order) => rejectedIds.has(order.id))
    .map((order) => ({ id: order.id, reason: 'insufficient_stock' }));
  const remaining = warehouses
    .flatMap((warehouse) => warehouse.lots
      .filter((lot) => lot.qty > 0)
      .map((lot) => ({
        warehouse: warehouse.id,
        sku: lot.sku,
        lot: lot.lot,
        qty: lot.qty,
        expires: lot.expires,
      })))
    .sort((left, right) => (
      left.warehouse.localeCompare(right.warehouse) ||
      left.sku.localeCompare(right.sku) ||
      left.expires.localeCompare(right.expires) ||
      left.lot.localeCompare(right.lot)
    ));

  return { accepted, rejected, remaining };
}

function runFulfillWave(argv) {
  try {
    const inputPath = parseInputFlag(argv);
    const input = JSON.parse(fs.readFileSync(inputPath, 'utf8'));
    process.stdout.write(`${JSON.stringify(fulfillWave(input))}\n`);
  } catch (error) {
    const message = error instanceof Error ? error.message : 'invalid input';
    process.stderr.write(`${JSON.stringify({ error: message })}\n`);
    process.exitCode = 2;
  }
}

function main(argv) {
  const [command, ...rest] = argv;

  if (!command || command === '--help' || command === '-h') {
    process.stdout.write(USAGE);
    return;
  }

  switch (command) {
    case 'hello': {
      const name = parseNameFlag(rest);
      console.log(`Hello, ${name}!`);
      return;
    }
    case 'version': {
      console.log(readPackageVersion());
      return;
    }
    case 'fulfill-wave': {
      runFulfillWave(rest);
      return;
    }
    default:
      console.error(`Unknown command: ${command}`);
      process.stderr.write(USAGE);
      process.exit(1);
  }
}

main(process.argv.slice(2));

