const { test } = require('node:test');
const assert = require('node:assert');
const { execFileSync, spawnSync } = require('node:child_process');
const fs = require('node:fs');
const os = require('node:os');
const path = require('node:path');

const CLI = path.join(__dirname, '..', 'bin', 'cli.js');

function run(args) {
  return execFileSync('node', [CLI, ...args], { encoding: 'utf8' });
}

test('hello default', () => {
  const out = run(['hello']);
  assert.match(out, /Hello, world!/);
});

test('hello with --name', () => {
  const out = run(['hello', '--name', 'alice']);
  assert.match(out, /Hello, alice!/);
});

test('version prints package version', () => {
  const out = run(['version']);
  assert.match(out, /\d+\.\d+\.\d+/);
});

function withInput(input, callback) {
  const directory = fs.mkdtempSync(path.join(os.tmpdir(), 'harbor-tools-'));
  const inputPath = path.join(directory, 'input.json');
  fs.writeFileSync(inputPath, JSON.stringify(input));
  try {
    callback(inputPath);
  } finally {
    fs.rmSync(directory, { recursive: true, force: true });
  }
}

test('fulfill-wave accepts orders by priority and uses FEFO allocations', () => {
  withInput({
    warehouses: [
      {
        id: 'west',
        distance: 2,
        lots: [
          { sku: 'widget', lot: 'new', qty: 4, expires: '2026-02-01' },
          { sku: 'widget', lot: 'old', qty: 3, expires: '2026-01-01' },
        ],
      },
    ],
    orders: [
      {
        id: 'later-priority',
        priority: 1,
        submitted_at: '2026-01-02T00:00:00Z',
        lines: [{ sku: 'widget', qty: 3, single_warehouse: false }],
      },
      {
        id: 'first-priority',
        priority: 2,
        submitted_at: '2026-01-03T00:00:00Z',
        lines: [{ sku: 'widget', qty: 2, single_warehouse: true }],
      },
    ],
  }, (inputPath) => {
    const result = JSON.parse(run(['fulfill-wave', '--input', inputPath]));
    assert.deepStrictEqual(result, {
      accepted: [
        {
          id: 'first-priority',
          allocations: [{ sku: 'widget', warehouse: 'west', lot: 'old', qty: 2 }],
        },
        {
          id: 'later-priority',
          allocations: [
            { sku: 'widget', warehouse: 'west', lot: 'old', qty: 1 },
            { sku: 'widget', warehouse: 'west', lot: 'new', qty: 2 },
          ],
        },
      ],
      rejected: [],
      remaining: [{
        warehouse: 'west', sku: 'widget', lot: 'new', qty: 2, expires: '2026-02-01',
      }],
    });
  });
});

test('fulfill-wave rolls back an all-or-nothing rejection', () => {
  withInput({
    warehouses: [
      {
        id: 'near',
        distance: 1,
        lots: [{ sku: 'widget', lot: 'lot-1', qty: 2, expires: '2026-01-01' }],
      },
      {
        id: 'far',
        distance: 2,
        lots: [{ sku: 'widget', lot: 'lot-2', qty: 2, expires: '2026-01-02' }],
      },
    ],
    orders: [
      {
        id: 'rejected-first',
        priority: 2,
        submitted_at: '2026-01-01',
        lines: [
          { sku: 'widget', qty: 2, single_warehouse: false },
          { sku: 'missing', qty: 1, single_warehouse: false },
        ],
      },
      {
        id: 'accepted-after-rollback',
        priority: 1,
        submitted_at: '2026-01-02',
        lines: [{ sku: 'widget', qty: 2, single_warehouse: true }],
      },
      {
        id: 'cannot-combine',
        priority: 3,
        submitted_at: '2026-01-03',
        lines: [{ sku: 'widget', qty: 3, single_warehouse: true }],
      },
    ],
  }, (inputPath) => {
    const result = JSON.parse(run(['fulfill-wave', '--input', inputPath]));
    assert.deepStrictEqual(result, {
      accepted: [{
        id: 'accepted-after-rollback',
        allocations: [{ sku: 'widget', warehouse: 'near', lot: 'lot-1', qty: 2 }],
      }],
      rejected: [
        { id: 'rejected-first', reason: 'insufficient_stock' },
        { id: 'cannot-combine', reason: 'insufficient_stock' },
      ],
      remaining: [{
        warehouse: 'far', sku: 'widget', lot: 'lot-2', qty: 2, expires: '2026-01-02',
      }],
    });
  });
});

test('fulfill-wave reports invalid input as one JSON stderr object', () => {
  withInput({
    warehouses: [],
    orders: [{
      id: 'invalid',
      priority: 1,
      submitted_at: 'not-a-date',
      lines: [],
    }],
  }, (inputPath) => {
    const result = spawnSync('node', [CLI, 'fulfill-wave', '--input', inputPath], {
      encoding: 'utf8',
    });
    assert.strictEqual(result.status, 2);
    assert.strictEqual(result.stdout, '');
    const error = JSON.parse(result.stderr);
    assert.ok(error && !Array.isArray(error));
  });
});

